with open(FILE, 'r') as f:
    data = json.load(f)

existing_ids = set()
for c in data:
    for item in c['items']:
        existing_ids.add(item['id'])

# Validate new categories
new_ids = set()
errors = []
for cat in new_categories:
    for item in cat['items']:
        if item['id'] in existing_ids:
            errors.append(f"DUPLICATE with existing: {item['id']}")
        if item['id'] in new_ids:
            errors.append(f"DUPLICATE within new: {item['id']}")
        new_ids.add(item['id'])
        if '_____' not in item['question']:
            errors.append(f"Missing blank in {item['id']}: {item['question'][:50]}")
        if len(item['options']) != 4:
            errors.append(f"Wrong option count in {item['id']}")
        if item['correct'] not in item['options']:
            errors.append(f"Correct not in options: {item['id']}")
        if len(item['explanation']) < 200:
            errors.append(f"Short explanation ({len(item['explanation'])} chars) in {item['id']}")

if errors:
    print("ERRORS:")
    for e in errors:
        print(f"  {e}")
else:
    data.extend(new_categories)
    with open(FILE, 'w') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    total_cats = len(data)
    total_items = sum(len(c['items']) for c in data)
    print(f"SUCCESS: {total_cats} categories, {total_items} items, 0 duplicates")
    print(f"New categories: {', '.join(c['key'] for c in new_categories)}")
